     1→// vim: fdm=marker
     2→
     3→configuration {
     4→  modes: "combi,window";
     5→  combi-modes: "script:~/.config/rofi/scripts/powermenu_entry,drun";
     6→  combi-hide-mode-prefix: true;
     7→  font: "JetBrainsMono NF 14";
     8→  drun-display-format: "{name}";
     9→  show-icons: false;
    10→  threads: 0;
    11→  lazy-grab: false;
    12→  drun-use-desktop-cache: false;
    13→  sort: false;
    14→  disable-history: true;
    15→}
    16→
    17→* {
    18→  bg:          #1c1c1e;
    19→  fg:          #ffffff;
    20→  fg-dim:      #ffffff99;
    21→  selected-bg: #A7C080;
    22→  selected-fg: #ffffff;
    23→  border-col:  #ffffff18;
    24→  t:           transparent;
    25→}
    26→
    27→window {
    28→  width:            680px;
    29→  background-color: @bg;
    30→  border-radius:    12px;
    31→  border:           0px;
    32→  location:         center;
    33→  padding:          12px;
    34→}
    35→
    36→mainbox {
    37→  background-color: @t;
    38→  spacing:          8px;
    39→  children:         [ inputbar, listview ];
    40→}
    41→
    42→inputbar {
    43→  background-color: #ffffff0f;
    44→  border-radius:    10px;
    45→  padding:          12px 16px;
    46→  spacing:          10px;
    47→  children:         [ prompt, entry ];
    48→}
    49→
    50→prompt {
    51→  background-color: @t;
    52→  text-color:       @fg-dim;
    53→  vertical-align:   0.5;
    54→}
    55→
    56→entry {
    57→  background-color: @t;
    58→  text-color:       @fg;
    59→  placeholder:      "Search apps...";
    60→  placeholder-color: @fg-dim;
    61→  vertical-align:   0.5;
    62→}
    63→
    64→case-indicator {
    65→  background-color: @t;
    66→  text-color:       @fg-dim;
    67→}
    68→
    69→listview {
    70→  background-color: @t;
    71→  border:           0;
    72→  padding:          4px 0 0;
    73→  lines:            8;
    74→  scrollbar:        false;
    75→  spacing:          2px;
    76→}
    77→
    78→element {
    79→  padding:          8px 12px;
    80→  children:         [ element-text ];
    81→}
    82→
    83→element-icon {
    84→  size:             24px;
    85→  background-color: @t;
    86→  vertical-align:   0.5;
    87→}
    88→
    89→element-text {
    90→  background-color: @t;
    91→  text-color:       @fg;
    92→  vertical-align:   0.5;
    93→}
    94→
    95→element.normal.normal {
    96→  background-color: @t;
    97→}
    98→element.selected.normal {
    99→  background-color: @selected-bg;
   100→  border-radius:    6px;
   101→}
   102→element.alternate.normal {
   103→  background-color: @t;
   104→}
   105→element.selected.normal element-text {
   106→  text-color: @selected-fg;
   107→}
   108→
   109→message {
   110→  background-color: @bg;
   111→  border:           0;
   112→  padding:          4px 0 0;
   113→}
   114→
